import { Button } from "@/components/ui/button";

const data = [
  {
    "variant": "default",
    "text": "Default"
  },
  {
    "variant": "secondary",
    "text": "Secondary"
  },
  {
    "variant": "destructive",
    "text": "Destructive"
  },
  {
    "variant": "outline",
    "text": "Outline"
  },
  {
    "variant": "ghost",
    "text": "Ghost"
  },
  {
    "variant": "link",
    "text": "Link"
  }
] as const;

export default function ButtonVariantsExample() {
  return (
    <div className="flex flex-wrap gap-3">
      {data.map((item, index) => (
        <Button key={index} variant={item.variant}>{item.text}</Button>
      ))}
    </div>
  );
}
